 1	import React, { FC, useCallback, useEffect, useState } from 'react';
 2	import { useLocation, useNavigate } from 'react-router-dom-v5-compat';
 3	
 4	import Loading from '@kubevirt-utils/components/Loading/Loading';
 5	import { VirtualMachineDetailsTab } from '@kubevirt-utils/constants/tabs-constants';
 6	import { vmSignal } from '@kubevirt-utils/store/customizeInstanceType';
 7	import { Tab, Tabs, TabTitleText } from '@patternfly/react-core';
 8	import VirtualMachineConfigurationTabSearch from '@virtualmachines/details/tabs/configuration/search/VirtualMachineConfigurationTabSearch';
 9	import {
10	  getInnerTabFromPath,
11	  includesConfigurationPath,
12	} from '@virtualmachines/details/tabs/configuration/utils/utils';
13	
14	import { tabs } from './utils/constants';
15	
16	import './CustomizeInstanceTypeConfigurationTab.scss';
17	
18	const CustomizeInstanceTypeConfigurationTab: FC = () => {
19	  const navigate = useNavigate();
20	  const location = useLocation();
21	  const [activeTabKey, setActiveTabKey] = useState<number | string>(
22	    VirtualMachineDetailsTab.Details,
23	  );
24	
25	  const vm = vmSignal.value;
26	
27	  const redirectTab = useCallback(
28	    (name: string) => {
29	      setActiveTabKey(name);
30	      const redirectPath = includesConfigurationPath(
31	        location.pathname,
32	        `${VirtualMachineDetailsTab.Configurations}/${name}`,
33	      );
34	      navigate(redirectPath);
35	    },
36	    [location.pathname, navigate],
37	  );
38	
39	  useEffect(() => {
40	    const innerTab = getInnerTabFromPath(location.pathname);
41	    innerTab && setActiveTabKey(innerTab);
42	  }, [location.pathname]);
43	
44	  if (!vm) {
45	    return <Loading />;
46	  }
47	
48	  return (
49	    <div className="co-dashboard-body ConfigurationTab">
50	      <VirtualMachineConfigurationTabSearch vm={vm} />
51	      <div className="ConfigurationTab--body">
52	        <Tabs activeKey={activeTabKey} className="ConfigurationTab--main" isVertical>
53	          {tabs.map(({ Component, name, title }) => (
54	            <Tab
55	              className="ConfigurationTab--content"
56	              data-test-id={`vm-configuration-${name}`}
57	              eventKey={name}
58	              key={name}
59	              onClick={() => redirectTab(name)}
60	              title={<TabTitleText>{title}</TabTitleText>}
61	            >
62	              {activeTabKey === name && <Component />}
63	            </Tab>
64	          ))}
65	        </Tabs>
66	      </div>
67	    </div>
68	  );
69	};
70	
71	export default CustomizeInstanceTypeConfigurationTab;

